  ('heelevel3-5ff21eeb-moex-00064', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'essay', '甲有 A 屋一間，因已閒置一年，決定出租。乙見 A 屋地段佳，甚為喜
歡，而與甲簽訂租賃契約承租 A屋，雙方約定租賃期間自民國 112 年 7
月 1 日起至民國 114 年 6 月 30 日止，乙當場支付三個月租金總額之押
租金予甲，並於隔日搬入居住。甲於民國113 年2 月 1 日將 A屋出售於
丙，並辦理所有權移轉登記完畢，丙以其為 A屋所有權人且未出租於乙
為由，要求乙搬離，乙則以其係向甲承租為由斷然拒絕，何人之主張有
理由？若丙未要求乙搬離，當租賃期間屆滿，乙搬離時，可否請求丙返
還押租金？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00065', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'essay', '甲、乙、丙共有A地一筆，應有部分各為三分之一。於民國 112年 9 月
起，丁未得共有人之同意，擅自於該地劃設三十個停車位，並以每個月
租金新臺幣五千元對外出租，三十個車位當即全數出租。甲於民國 113
年 3 月發現 A 地為丁所占用，甲可否要求丁將 A 地及占用 A 地期間所
收取租金返還於自己？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00066', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '未保留胎兒應繼分之遺產協議分割行為，其效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00067', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲將一平板電腦借乙使用，乙使用時，好友丙見到，非常羨慕，表示願以高價購買之，乙見機不 可失，遂以自己名義賣與丙，並將該平板電腦交付於丙。有關乙、丙間之法律行為，下列敘述， 何者正確？', '["債權行為與物權行為均無效", "債權行為與物權行為均效力未定", "債權行為效力未定，物權行為無效", "債權行為有效，物權行為效力未定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00068', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列何種請求權，有消滅時效規定之適用？', '["分割共有物之請求權", "已登記不動產所有人之除去妨害請求權", "夫妻間侵權行為而生之損害賠償請求權", "夫妻關係而生之同居請求權 32020"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00069', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲有A跑車一部，A車因車禍致車體毀損。甲擅自取乙所有之油漆漆於A車，並向偷車集團購買 丙所有之同類新型引擎一個，安裝於A車。其後甲又將A車讓售於惡意之丁。下列敘述，何者正確？', '["甲取得油漆之所有權，乙得依不當得利規定向甲請求償金", "甲取得引擎之所有權，丙得依不當得利規定向甲請求償金", "甲有權處分A車，丁不僅取得A車之所有權，亦取得油漆及引擎之所有權", "乙得以其所有權受侵害為由，對惡意之丁主張侵權行為之損害賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00070', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於錯誤意思表示之敘述，何者錯誤？', '["甲欲與乙畫家締約，使乙畫家為甲畫肖像，但卻將丙畫家認為是乙畫家而與丙畫家締約，甲無 過失時，得撤銷其與丙間之契約", "甲欲向丁購買A馬，卻未注意誤以為B馬為A馬而購買之，則甲得撤銷其與丁間之契約", "甲內心欲以新臺幣（下同）300萬元出賣C車予戊，於書寫時寫成30萬元，甲無過失時，得撤 銷其與戊間之契約", "甲以為前來應徵之庚，係曾在美國留學3年取得學位而與其訂立僱傭契約，甲無過失時，得撤 銷其與庚間之契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00071', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於附停止條件法律行為之敘述，何者錯誤？', '["須以將來不確定之事實為法律行為附款", "是法律行為之生效要件", "條件成就時，縱無特約，皆回溯自約定條件時生效", "條件成就前，尚未發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00072', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲竊取乙於丙銀行存款之存摺、印章及密碼後，於乙察覺遭竊前，甲持乙之印章、存摺及密碼至 丙銀行櫃臺，佯稱自己為乙，盜領乙之存款新臺幣十萬元。丙銀行於下列何種情形，得主張其已 對乙清償上述存款之債務？', '["丙須不知甲非債權人而為給付", "丙須無重大過失不知甲非債權人而為給付", "丙須無具體輕過失不知甲非債權人而為給付", "丙須無抽象輕過失不知甲非債權人而為給付"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00073', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '當事人無特約之情形下，下列何者無收取擔保物所生天然孳息之權利？', '["典權人", "扣押抵押物前之抵押權人", "動產質權人", "留置權人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
